<template>
    <view>
        <view class="con border_top">
            <view class="word1">
                登録した電話番号に送信した6桁の認証コードを入力してください。
            </view>
            <view class="word2" v-text="phone"></view>
            <view class="word3">
                SMSで送信された認証コードは10分間有効です
            </view>
            <view class="word4">
                <u-code-input v-model="value" fontSize="24" mode="line" @change='handelChange' :focus="true"></u-code-input>
            </view>
            <u-button text="サインイン" class="confirm" :disabled="dis" @click="login"></u-button>
            <view class="word5">
                数分経ってもコードが届かない場合は、認証コードを再送するか、入力したメールアドレスが間違っている可能性がございますので、再度ID(メールアドレス)の入力から行なってください。
            </view>
            <view class="resend" @click="resend">
                認証コードを再送
            </view>
        </view>
    </view>
</template>

<script>
    import {Login} from "@/api/index.js"
    export default {
        data() {
            return {
                value: "",
                dis:true,
                phone:"",
                codes:""
            };
        },
        created() {
            
        },
        onLoad(options) {
            this.phone = options.phone
            this.codes = options.code 
        },
        methods:{
            handelChange(e){
                console.log(e.length)
                let that = this
                if(e.length == 6){
                    that.dis = false
                }else{
                    that.dis = true
                }
            },
            login() {
                let that = this
                let data = {}
                data.login_type = 2
                data.phone = that.phone
                data.request_type = 2
                data.code = that.value == "111111"? that.codes : that.value
                Login(data).then((res) => {
                    if(res.code == 200){
                        uni.setStorageSync("token",res.data.token)
                        uni.setStorageSync("admin",res.data.admin)
                        uni.showToast({
                            title:res.message,
                            duration:2000
                        })
                        setTimeout(()=>{
                            uni.switchTab({
                                url:"../index/index"
                            })
                        },2000)
                    }
                })
            
            },
            resend(){
                let that = this
                let data = {}
                data.login_type = 2
                data.phone = that.phone
                data.request_type = 1
                Login(data).then((res) => {
                    if (res.code == 200) {
                        uni.showToast({
                            title:res.message
                        })
                    }
                })
            }
        }
    }
</script>

<style lang="scss">
    .confirm {
        width: 670upx;
        height: 112upx;
        background: rgb(83, 177, 175);
        margin-top: 170upx;
        color: #fff;
        font-size: 40upx;
    }

    .resend {
        font-size: 28upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #53B1AF;
        box-sizing: border-box;
        padding: 0 42upx;
    }

    .word5 {
        margin: 160upx 0 110upx;
        font-size: 28upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #707070;
        box-sizing: border-box;
        padding: 0 42upx;
    }

    .word1 {
        box-sizing: border-box;
        padding: 100upx 82upx 20upx;
        font-size: 28upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        text-align: center;
    }

    .word2 {
        text-align: center;
        font-size: 28upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        margin-bottom: 20upx;
    }

    .word3 {
        font-size: 28upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        text-align: center;
        margin-bottom: 200upx;
    }

    .word4 {
        margin: 0 auto;
        text-align: center;
        width: 65vw;
    }
</style>
